    files_to_zip.append(str(csv))
    print(f'  ✓ {csv}')

if files_to_zip:
    !zip -r digisteel_v2_results.zip {' '.join(files_to_zip)}
    print(f'\n✓ Packaged {len(files_to_zip)} files')
    files.download('digisteel_v2_results.zip')
else:
